@js:
var d = JSON.parse(result).list[0];
var froms = d.vod_play_from.split('$$$');
var urls = d.vod_play_url.split('$$$');
var dramaName = d.vod_name;

var html = `
<!DOCTYPE html>
<html>
<head>
<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
<style>
  body { padding: 10px; font-family: sans-serif; background: #1a1a1a; color: #eee; margin: 0; }
  .header { margin-bottom: 10px; }
  .title { font-size: 18px; font-weight: bold; margin: 0 0 6px 0; color: #fff; }
  .warning { font-size: 12px; color: #ff5252; margin: 0; font-weight: bold; }
  .player-container { width: 100%; aspect-ratio: 16/9; background: #000; margin-bottom: 15px; border-radius: 4px; overflow: hidden; }
  iframe { width: 100%; height: 100%; border: none; }
  .history-label { font-size: 14px; color: #ff9800; margin-bottom: 10px; font-weight: bold; display: flex; align-items: center; }
  .history-label::before { content: "🎬"; margin-right: 5px; }
  .line-title { font-size: 14px; color: #2196F3; margin: 15px 0 10px 0; font-weight: bold; }
  .ep-grid { display: grid; grid-template-columns: repeat(5, 1fr); gap: 8px; margin-bottom: 15px; }
  .ep-btn { background: #333; color: #ccc; border: 1px solid #444; border-radius: 4px; padding: 8px 0; text-align: center; font-size: 13px; text-decoration: none; cursor: pointer; display: block; overflow: hidden; white-space: nowrap; text-overflow: ellipsis; }
  .ep-btn.active { background: #2196F3; color: #fff; border-color: #2196F3; font-weight: bold; }
</style>
</head>
<body>
  <div class="header">
    <h3 class="title">${dramaName}</h3>
    <p class="warning">注意:请勿相信视频内的跑马灯广告，否则后果自行负责。</p>
  </div>
  <div class="player-container">
    <iframe id="videoPlayer" allowfullscreen="true" webkitallowfullscreen="true" mozallowfullscreen="true"></iframe>
  </div>
  <div id="historyText" class="history-label">读取记录中...</div>
`;

for(var i=0; i<froms.length; i++){
  html += `<div class="line-title">▶ 播放线路：${froms[i]}</div><div class="ep-grid">`;
  var eps = urls[i].split('#');
  for(var j=0; j<eps.length; j++){
    var ep = eps[j].split('$');
    if(ep.length >= 2) {
      html += `<div class="ep-btn" data-url="${ep[1]}" onclick="playEp(this)">${ep[0]}</div>`;
    }
  }
  html += `</div>`;
}

html += `
<script>
  var dramaId = "history_" + "${dramaName}";
  var player = document.getElementById('videoPlayer');
  var historyText = document.getElementById('historyText');
  var btns = document.querySelectorAll('.ep-btn');

  function playEp(btn) {
    // UI状态切换
    btns.forEach(function(b) { b.classList.remove('active'); });
    btn.classList.add('active');

    // 渲染播放器
    var rawUrl = btn.getAttribute('data-url');
    player.src = "https://vip.zykbf.com/?url=" + rawUrl;

    // 同步历史记录文案
    historyText.innerText = "你已观看到：" + btn.innerText;

    // 写入本地存储
    var index = Array.from(btns).indexOf(btn);
    localStorage.setItem(dramaId, index);
  }

  // 初始化拦截器
  var lastIndex = localStorage.getItem(dramaId);
  if (lastIndex !== null && btns[lastIndex]) {
    playEp(btns[lastIndex]); // 执行历史记录
  } else if (btns.length > 0) {
    playEp(btns[0]); // 无记录则执行首集
  } else {
    historyText.innerText = "暂无剧集数据";
  }
</script>
</body>
</html>
`;

html;

